<script setup>
import{onBeforeUnmount,onMounted,reactive,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';import{useAuthStore}from'../stores/auth';import{useInventoryStore}from'../stores/inventory';
const auth=useAuthStore(),inventory=useInventoryStore(),message=ref(''),editing=ref(null),showForm=ref(false);const empty={name:'',sku:'',barcode:'',category:'Materials',supplier:'',unit:'pcs',price:0,stock_quantity:0,safety_stock:0,reorder_level:10,discount_percent:0};const form=reactive({...empty});
onMounted(async()=>{await inventory.load();inventory.start()});onBeforeUnmount(()=>inventory.stop());
function open(p=null){editing.value=p;Object.assign(form,p||empty);showForm.value=true}async function save(){try{editing.value?await axios.put(`/api/products/${editing.value.id}`,form):await axios.post('/api/products',form);showForm.value=false;message.value='Product saved.';await inventory.load()}catch(e){message.value=e.response?.data?.message||'Unable to save product.'}}
async function adjust(p){const value=prompt(`Stock change for ${p.name}. Use a negative number to deduct.`);if(!value||Number(value)===0)return;const reason=prompt('Reason for adjustment:');if(!reason)return;try{await axios.post(`/api/products/${p.id}/adjust`,{quantity_delta:Number(value),reason});message.value='Stock adjusted and logged.';await inventory.load()}catch(e){message.value=e.response?.data?.message||'Adjustment failed.'}}
</script>
<template><PageHeader title="Inventory" subtitle="Exact on-hand, reserved, and sellable quantities"><button v-if="auth.role==='admin'" class="btn primary" @click="open()">Add product</button></PageHeader><p v-if="message" class="notice">{{message}}</p><section class="panel table-wrap"><table><thead><tr><th>Product</th><th>SKU / barcode</th><th>On hand</th><th>Reserved</th><th>Available</th><th>Price</th><th>Status</th><th v-if="auth.role==='admin'">Actions</th></tr></thead><tbody><tr v-for="p in inventory.products" :key="p.id"><td><strong>{{p.name}}</strong><small>{{p.category}} · {{p.supplier}}</small></td><td>{{p.sku}}<small>{{p.barcode}}</small></td><td>{{p.stock_quantity}} {{p.unit}}</td><td>{{p.reserved_quantity}}</td><td><strong>{{p.available_quantity}}</strong></td><td>₱{{Number(p.price).toLocaleString()}}</td><td><span class="tag" :class="{warn:p.is_low_stock}">{{p.is_low_stock?'Reorder':'Healthy'}}</span></td><td v-if="auth.role==='admin'"><div class="actions"><button class="btn tiny" @click="open(p)">Edit</button><button class="btn tiny" @click="adjust(p)">Adjust</button></div></td></tr></tbody></table></section><div v-if="showForm" class="modal"><form class="modal-card wide" @submit.prevent="save"><div class="panel-head"><h2>{{editing?'Edit':'Add'}} product</h2><button type="button" class="btn ghost" @click="showForm=false">Close</button></div><div class="form-grid"><label>Name<input v-model="form.name" required></label><label>SKU<input v-model="form.sku" required></label><label>Barcode<input v-model="form.barcode" required></label><label>Category<input v-model="form.category" required></label><label>Supplier<input v-model="form.supplier"></label><label>Unit<input v-model="form.unit" required></label><label>Price<input v-model.number="form.price" type="number" min=".01" step=".01" required></label><label v-if="!editing">Opening stock<input v-model.number="form.stock_quantity" type="number" min="0"></label><label>Safety stock<input v-model.number="form.safety_stock" type="number" min="0"></label><label>Reorder level<input v-model.number="form.reorder_level" type="number" min="0"></label><label>Discount %<input v-model.number="form.discount_percent" type="number" min="0" max="100"></label></div><button class="btn primary">Save product</button></form></div></template>
